Trace the data: what does the UserGreeting component display when App renders?

```jsx
function App() {
  const user = { firstName: "Dana", lastName: "Park", plan: "Pro" };

  return (
    <div>
      <UserGreeting
        name={user.firstName}
        tier={user.plan}
      />
    </div>
  );
}

function UserGreeting({ name, tier = "Free" }) {
  return (
    <div>
      <h1>Hello, {name}</h1>
      <p>Your plan: {tier}</p>
    </div>
  );
}
```

