Read this multi-component setup and determine: what does the page display when the order has 2 items?

```jsx
function OrderPage() {
  const order = {
    items: [
      { id: "i1", name: "Notebook", price: 12.99 },
      { id: "i2", name: "Pen Set", price: 8.49 },
    ],
    discount: 0,
  };

  const total = order.items.reduce((sum, item) => sum + item.price, 0);

  return (
    <div>
      <h1>Your Order</h1>
      <ItemList items={order.items} />
      {order.discount > 0 && (
        <p className="discount">Discount applied!</p>
      )}
      <OrderTotal amount={total} />
    </div>
  );
}

function ItemList({ items }) {
  return (
    <ul>
      {items.map(item => (
        <li key={item.id}>
          {item.name} - ${item.price}
        </li>
      ))}
    </ul>
  );
}

function OrderTotal({ amount }) {
  return <p className="total">Total: ${amount.toFixed(2)}</p>;
}
```
